// Validate incoming file and generate request ID
const item = $input.item;
const bin = item.binary?.file;
if (!bin) throw new Error('No file attached in field "file"');

const mime = bin.mimeType || '';
const fileName = bin.fileName || 'unknown';
const fileExt = (fileName.split('.').pop() || '').toLowerCase();

let fileType = 'unknown';
if (mime.includes('wordprocessingml') || fileExt === 'docx') fileType = 'docx';
else if (mime.includes('pdf') || fileExt === 'pdf') fileType = 'pdf';

if (fileType === 'unknown') {
  throw new Error('Unsupported file type: ' + mime + ' (.' + fileExt + ')');
}

if ((bin.fileSize || 0) > 20 * 1024 * 1024) {
  throw new Error('File too large (max 20MB)');
}

const requestId = 'REQ-' + new Date().getFullYear() + '-' +
  String(Math.floor(Math.random() * 90000 + 10000));

return {
  json: {
    request_id: requestId,
    file_name: fileName,
    file_type: fileType,
    file_size: bin.fileSize || 0,
    mime_type: mime,
    received_at: new Date().toISOString(),
    received_ts: Date.now()
  },
  binary: item.binary
};

// Parse Claude response, normalize, classify vehicle
const resp = $input.item.json;
const text = resp?.content?.[0]?.text || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude returned non-JSON: ' + text.slice(0, 300));
}

const ctx = $('Validate File').item.json;

function classifyVehicle(pax) {
  if (pax <= 2) return 'sedan';
  if (pax <= 4) return 'minivan';
  if (pax <= 8) return 'van';
  if (pax <= 12) return 'midibus';
  return 'bus';
}

const totalSegments = (parsed.days || [])
  .reduce((n, d) => n + (d.transfers?.length || 0), 0);

return {
  json: {
    request_id: ctx.request_id,
    source_file_name: ctx.file_name,
    source_file_type: ctx.file_type,
    source_file_size: ctx.file_size,
    tour_name: parsed.tour_name,
    dmc_hint: parsed.dmc_hint,
    pax_count: parsed.pax_count,
    vehicle_category: classifyVehicle(parsed.pax_count),
    ai_confidence: parsed.confidence,
    tour_starts_on: parsed.tour_starts_on,
    tour_ends_on: parsed.tour_ends_on,
    cities_covered: (parsed.cities || []).map(c => c.toLowerCase()),
    total_segments: totalSegments,
    total_days: (parsed.days || []).length,
    days: parsed.days,
    parse_raw_output: parsed,
    parse_duration_ms: Date.now() - ctx.received_ts,
    status: 'parsed'
  }
};

// Prepare segments for bulk insert
const req = $('Normalize Data').item.json;
const insertedId = $input.item.json.id;

const rows = [];
let seq = 0;
for (const day of req.days || []) {
  for (const t of (day.transfers || [])) {
    seq++;
    rows.push({
      request_id: insertedId,
      day_number: day.day_number,
      transfer_date: day.date,
      sequence: t.sequence || seq,
      time_from: t.time_from,
      time_to: t.time_to,
      travel_duration_minutes: t.travel_minutes || 0,
      location_from: t.location_from,
      location_to: t.location_to,
      city_from: (t.city_from || '').toLowerCase(),
      city_to: (t.city_to || '').toLowerCase(),
      dispatch_city: (t.dispatch_city || t.city_from || '').toLowerCase(),
      is_intercity: !!t.is_intercity
    });
  }
}

return rows.map(r => ({ json: r }));

// Build final dashboard response
const req = $('Normalize Data').item.json;
const requestDbId = $('Supabase · Insert Request').item.json.id;
const pairs = $('Get City-Day Pairs').all().map(i => i.json);
const allDrivers = $input.all().map(i => i.json);

// Group drivers by their pairing item
const assignments = pairs.map((pair, idx) => {
  const drivers = allDrivers.filter(d => d && d.driver_id);
  const top = drivers[idx] || drivers[0];
  return {
    city: pair.dispatch_city,
    date: pair.transfer_date,
    suggested: top ? {
      id: top.driver_id,
      name: top.full_name,
      rating: Number(top.rating),
      trips: top.trips_completed
    } : null
  };
});

// Build structure compatible with dashboard UI
const uniqueCities = [...new Set(assignments.map(a => a.city))];
const cityToDriver = {};
assignments.forEach(a => {
  if (a.suggested && !cityToDriver[a.city]) {
    const initials = a.suggested.name.split(' ').map(p => p[0]).slice(0,2).join('');
    cityToDriver[a.city] = {
      city: a.city,
      driver: a.suggested.name,
      initials,
      status: 'confirmed'
    };
  }
});

const assignmentsByDay = {};
(req.days || []).forEach(day => {
  const dayAssignments = [];
  const citiesInDay = [...new Set((day.transfers || []).map(t => (t.dispatch_city || t.city_from || '').toLowerCase()))];
  citiesInDay.forEach(c => {
    if (cityToDriver[c]) dayAssignments.push(cityToDriver[c]);
  });
  assignmentsByDay[day.day_number] = dayAssignments;
});

const recommended = allDrivers
  .filter(d => d && d.driver_id)
  .slice(0, 4)
  .map(d => ({
    name: d.full_name,
    city: 'N/A',
    car: 'Info from DB',
    plate: d.license_plate,
    rating: Number(d.rating),
    trips: d.trips_completed,
    status: 'available'
  }));

return {
  json: {
    request_id: req.request_id,
    request_db_id: requestDbId,
    dmc: req.dmc_hint || 'Unknown',
    tour_name: req.tour_name,
    pax: req.pax_count,
    vehicle_type: req.vehicle_category,
    parsing_confidence: req.ai_confidence,
    parsing_duration_ms: req.parse_duration_ms,
    days: (req.days || []).map(d => ({
      day_number: d.day_number,
      date: d.date,
      date_display: d.date ? d.date.split('-').reverse().join('.') : '',
      transfers: (d.transfers || []).map(t => ({
        time_from: t.time_from,
        time_to: t.time_to,
        from: t.location_from,
        to: t.location_to,
        travel: minutesToHHMM(t.travel_minutes),
        city: (t.dispatch_city || t.city_from || '').toLowerCase()
      })),
      empty_reason: d.empty_reason
    })),
    assignments: assignmentsByDay,
    recommended_drivers: recommended
  }
};

function minutesToHHMM(m) {
  if (!m) return '00:00:00';
  const h = Math.floor(m / 60);
  const mm = m % 60;
  return `${String(h).padStart(2,'0')}:${String(mm).padStart(2,'0')}:00`;
}
